<!DOCTYPE html>
<html lang="en">

<head>
    <meta charset="UTF-8">
    <title>Design Your Shirt</title>
    <style>
        body {
            font-family: Arial, sans-serif;
            padding: 30px;
        }

        .color-picker {
            margin-bottom: 20px;
        }

        .color-option {
            width: 40px;
            height: 40px;
            display: inline-block;
            margin-right: 10px;
            border-radius: 50%;
            border: 2px solid #ccc;
            cursor: pointer;
        }

        #shirt-container {
            position: relative;
            width: 400px;
            height: 500px;
            border: 1px solid #ddd;
        }

        svg {
            width: 100%;
            height: 100%;
            cursor: pointer;
        }
    </style>

    <!-- jQuery CDN -->
    <script src="https://code.jquery.com/jquery-3.6.0.min.js"></script>
</head>

