    <script>
        $(document).ready(function() {
            let selectedColor = '#ff0000';

            // Color selection
            $('.color-option').on('click', function() {
                selectedColor = $(this).data('color');
            });

            // Clickable SVG parts
            $('#shirt-container svg').on('click', function(e) {
                const target = e.target;

                if (target.tagName === 'rect' || target.tagName === 'circle' || target.tagName === 'path') {
                    target.setAttribute('fill', selectedColor);
                    target.style.fill = selectedColor;
                    console.log("Element updated:", target.id || target.tagName);
                }
            });
        });
        let isDragging = false;
let offsetX, offsetY;

$('#logo').on('mousedown', function(e) {
    isDragging = true;

    let logo = this;
    offsetX = e.offsetX - parseFloat(logo.getAttribute('x'));
    offsetY = e.offsetY - parseFloat(logo.getAttribute('y'));
});

$(document).on('mousemove', function(e) {
    if (isDragging) {
        let svgOffset = $('svg')[0].getBoundingClientRect();

        let x = e.clientX - svgOffset.left - offsetX;
        let y = e.clientY - svgOffset.top - offsetY;

        $('#logo').attr('x', x);
        $('#logo').attr('y', y);
    }
});

$(document).on('mouseup', function() {
    isDragging = false;
});
    </script>

